insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-01-24','(Pedro)Conversación con Javier (CRR Mérida). +++Ha vuelto Manuel. Tenía que volver mañana pero tuvo un incidente en el centro Vida de Cáceres y se marchó a su piso, donde vió que no tenía luz ni agua, por lo que decidió volver al centro. +++Lo pactado erea, como medida, volver mañana. Han optado por buscarle un hostal en Mérida para pasar la noche, le han dado comida y cena para hoy y mañana se pasarán por el banco para sacar los 200€ y paghar en el hostal los 20€ que cuesta. +++Fijamos reunión para mañana a la s 12:00 en el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-01-24','(Pedro) Reunión en el CSS Plasencia con Soraya (Directora), Agapito (Psiquiatra), Soraya (Jefa Unidad Programas). +++SE plantea traer a Margarita el 1 de febrero, en principio, a la zona residencial de mujeres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2018-01-24','INGRESO "Me pongo en contacto para informar acerca delingreso en la Unidad de Hospitalización Breve del Hospital de Llerena de David...en el día de hoy. Cuando se produzca el alta os lo comunico para que os quede constancia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-01-25','(Pedro) Conversación con Amparo, Residencia "El Cuartillo" (22140). +++El ingreso de Dª Antonia se realizó el pasado lunes 22 de enero como estaba previsto, sin que a su llegada se plantease ningún problema relevante para el mismo. +++En estos momentos se encuentra bien, comentando que cuando se ponga mejor ya le ha dicho al médico que volverá a casa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Pilar (Enfermera de Cilleros). +++SE le informa de la situación actual de Dª Antonia en la Residencia. +++Comenta que tampoco hubo problemas significativos cuando se llevó a cabo el traslado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Carmen, T. Soc. SSB de Cilleros. No está hoy en la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2018-01-25','-AMALIA: SE ENVIA AL CENTRO RESIDENCIAL LAS CRUCES SOLIICITUD DE RECONOCIMIENTO DEL GRADO DE DISCAPACIDAD.','2');
